import numpy as np

# {The new algorithm selects the next node by minimizing the weighted sum of the distance to the current node and the inverse of the sum of distances to all truck routes, emphasizing both proximity and overall centrality.}

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    available_nodes = set(unvisited_nodes) - {current_node}
    if not available_nodes:
        return None

    best_score = float('inf')
    next_node = None

    for node in available_nodes:
        distance_to_current = distance_matrix[current_node][node]

        sum_truck_distance = sum(distance_matrix[node][t_node] for t_node in truck_nodes) + 1e-5  # Avoid division by zero

        score = distance_to_current + (1 / sum_truck_distance)

        if score < best_score:
            best_score = score
            next_node = node

    return next_node

